<script>
// import VanillaTilt from 'vanilla-tilt';
export default {
  name: "Home",
  components: {},
  created() {
    const yourDate = new Date("2020-10-26T08:49:00");
    document.addEventListener(
      "DOMContentLoaded",
      function () {
        var rootTime = document.querySelector("time");

        document.getElementById("anni").innerHTML = `${
          yourDate.getDate() > 9 ? yourDate.getDate() : "0" + yourDate.getDate()
        } - 
        ${
          yourDate.getMonth() > 8
            ? yourDate.getMonth() + 1
            : "0" + (yourDate.getMonth() + 1)
        } - 
        ${yourDate.getFullYear()}`;

        document.getElementById("date").innerHTML =
          Math.floor(
            Math.floor((new Date() - yourDate) / 1000) / 60 / 60 / 24
          ) + " NGÀY";

        function olock() {
          var today = new Date(),
            hrs =
              Math.floor(Math.floor((today - yourDate) / 1000) / 60 / 60) % 24,
            min = Math.floor(Math.floor((today - yourDate) / 1000) / 60) % 60,
            sec = Math.floor((today - yourDate) / 1000) % 60;
          rootTime.textContent = `${hrs > 9 ? hrs : "0" + hrs} : 
          ${min > 9 ? min : "0" + min} : 
          ${sec > 9 ? sec : "0" + sec}`;
        }
        olock();
        setInterval(function () {
          olock();
        }, 1000);
        document
          .getElementsByTagName("body")[0]
          .insertAdjacentHTML("beforeend", "<div id='mask'></div>");
      },
      false
    );

    // VanillaTilt.init(document.querySelector(".vanilla-tilt"), {
    //   max: 25,
    //   speed: 400
    // });
  },
};
